from ag2.tools import tool

@tool
def read_repo_file(file_path: str) -> str:
    """Read file from repository context"""
    with open(file_path, 'r') as f:
        return f.read()

@tool
def list_repo_files(dir_path: str = ".") -> list:
    """List files in repository directory"""
    import os
    return [f for f in os.listdir(dir_path) if f.endswith(('.py', '.js'))]

generator.tools = [read_repo_file, list_repo_files]

def run_coding_session(task: str):
    generator.initiate_chat(
        manager,
        message=task + "\nRepo context: use read_repo_file tool"
    )

    while not tester.last_message().get('test_passed', False):
        manager.run_chat()

    return generator.last_message()['content']

