@vex.guardrail(verifications=["code_correctness", "security_vulnerability_scanning"])
def verify_generated_code(code: str, context: str) -> dict:
    """Verify code before execution"""
    result = vex.verify_code(code, context=context)

    issues = []
    if result.security_issues:
        issues.append("SECURITY: " + str(result.security_issues))
    if result.static_analysis_errors:
        issues.append("CORRECTNESS: " + str(result.static_analysis_errors))

    return {
        "safe_to_execute": len(issues) == 0,
        "issues": issues,
        "clean_code": result.cleaned_code if result.cleaned_code else code
    }

tester.message_hook = verify_generated_code
